def calculate_mirr_discounting():
    # Given project cash flows
    cash_flows = [-12000, 5800, 6500, 6200, 5100, -4300]
    # Interest rate (both discount and reinvestment)
    discount_rate = 0.10

    # Calculate the PV of all negative cash flows at Time 0
    pv_negatives = 0
    for t, flow in enumerate(cash_flows):
        if flow < 0:
            pv_negatives += flow / (1 + discount_rate)**t

    # Form the adjusted cash flow stream for the "discounting approach":
    # 1. Discount all negative cash flows back to Year 0.
    # 2. Leave all positive cash flows at their respective times.
    # The result is a stream where the only negative flow is at Year 0.
    adjusted_cash_flows = [0.0] * len(cash_flows)
    adjusted_cash_flows[0] = pv_negatives
    for t, flow in enumerate(cash_flows):
        if t > 0 and flow > 0:
            adjusted_cash_flows[t] = flow

    # The MIRR is the IRR of this adjusted cash flow stream.
    # We solve for 'r' in: sum(cf_t / (1 + r)**t) = 0
    def compute_npv(rate, cfs):
        return sum(cf / (1 + rate)**t for t, cf in enumerate(cfs))

    # Using binary search to find the root of the NPV function
    low_rate = -0.9999
    high_rate = 10.0
    for _ in range(100):
        mid_rate = (low_rate + high_rate) / 2
        if compute_npv(mid_rate, adjusted_cash_flows) > 0:
            low_rate = mid_rate
        else:
            high_rate = mid_rate

    return low_rate

if __name__ == "__main__":
    mirr_discounting = calculate_mirr_discounting()
    print(mirr_discounting)

