import math

def calculate_mirr_discounting():
    # Given project cash flows from the table
    # Year 0 to Year 5
    cash_flows = [-12000, 5800, 6500, 6200, 5100, -4300]
    # The project interest rate/cost of capital
    discount_rate = 0.10

    # The MIRR discounting approach (Ross Method 1):
    # 1. Discount all negative cash flows (except Year 0) back to Year 0 at the financing rate.
    # 2. Add these present values to the initial Year 0 cost.
    # 3. Calculate the IRR for the adjusted cash flow stream.

    # Step 1: Calculate the present value of all negative cash flows
    pv_neg_cfs = cash_flows[0]
    for year in range(1, len(cash_flows)):
        if cash_flows[year] < 0:
            pv_neg_cfs += cash_flows[year] / ((1 + discount_rate) ** year)

    # Step 2: Create the adjusted cash flow stream
    # Negative flows are moved to Year 0, and their original positions become 0.
    adj_cash_flows = [0.0] * len(cash_flows)
    adj_cash_flows[0] = pv_neg_cfs
    for year in range(1, len(cash_flows)):
        if cash_flows[year] > 0:
            adj_cash_flows[year] = cash_flows[year]
        else:
            adj_cash_flows[year] = 0.0

    # Step 3: Calculate the Internal Rate of Return (IRR) of the adjusted stream
    def npv(rate, cfs):
        """Computes the Net Present Value for a given rate and cash flow series."""
        return sum(cf / ((1 + rate) ** i) for i, cf in enumerate(cfs))

    def npv_derivative(rate, cfs):
        """Computes the derivative of the NPV with respect to the rate."""
        return sum(-i * cf / ((1 + rate) ** (i + 1)) for i, cf in enumerate(cfs))

    def irr(cfs, initial_guess=0.10):
        """Finds the IRR using the Newton-Raphson root-finding method."""
        rate = initial_guess
        for _ in range(100):
            current_npv = npv(rate, cfs)
            if abs(current_npv) < 1e-12:
                return rate
            deriv = npv_derivative(rate, cfs)
            if deriv == 0:
                break
            rate -= current_npv / deriv
        return rate

    # The resulting rate is the MIRR using the discounting approach
    mirr_discounting = irr(adj_cash_flows)
    return mirr_discounting

if __name__ == "__main__":
    answer = calculate_mirr_discounting()
    print(answer)

